package com.payment.module.security

import android.util.Log
import java.text.SimpleDateFormat
import java.util.*

object SecurityAuditLog {
    private const val TAG = "PaymentSecurity"
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)

    private val auditEntries = mutableListOf<AuditEntry>()

    data class AuditEntry(
        val timestamp: Long = System.currentTimeMillis(),
        val event: String,
        val severity: Severity,
        val details: String = ""
    )

    enum class Severity {
        INFO, WARNING, CRITICAL
    }

    fun logEvent(event: String, severity: Severity = Severity.INFO, details: String = "") {
        val entry = AuditEntry(event = event, severity = severity, details = details)
        synchronized(auditEntries) {
            auditEntries.add(entry)
            // Keep only last 1000 entries in memory
            if (auditEntries.size > 1000) {
                auditEntries.removeAt(0)
            }
        }

        val formattedTime = dateFormat.format(Date(entry.timestamp))
        when (severity) {
            Severity.INFO -> Log.i(TAG, "[$formattedTime] $event $details")
            Severity.WARNING -> Log.w(TAG, "[$formattedTime] $event $details")
            Severity.CRITICAL -> Log.e(TAG, "[$formattedTime] $event $details")
        }
    }

    fun getRecentEntries(count: Int = 50): List<AuditEntry> {
        synchronized(auditEntries) {
            return auditEntries.takeLast(count).toList()
        }
    }
}

