package com.payment.module.billing

import android.app.Activity
import android.content.Context
import com.android.billingclient.api.*
import com.payment.module.model.*
import com.payment.module.security.DataSanitizer
import com.payment.module.security.SecurityAuditLog
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow

class BillingManager(
    private val context: Context,
    private val onPurchaseCompleted: ((PaymentResult<Transaction>) -> Unit)? = null
) : PurchasesUpdatedListener {

    private var billingClient: BillingClient? = null
    private val coroutineScope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    private val _connectionState = MutableStateFlow(false)
    val connectionState: StateFlow<Boolean> = _connectionState.asStateFlow()

    private val _availableProducts = MutableStateFlow<List<ProductInfo>>(emptyList())
    val availableProducts: StateFlow<List<ProductInfo>> = _availableProducts.asStateFlow()

    private val pendingPurchases = mutableMapOf<String, Transaction>()

    init {
        initializeBillingClient()
    }

    private fun initializeBillingClient() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        startConnection()
    }

    private fun startConnection() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _connectionState.value = true
                    SecurityAuditLog.logEvent("Billing client connected successfully")
                    // Check for pending purchases
                    coroutineScope.launch {
                        processPendingPurchases()
                    }
                } else {
                    _connectionState.value = false
                    SecurityAuditLog.logEvent(
                        "Billing client connection failed",
                        SecurityAuditLog.Severity.WARNING,
                        "Response code: ${billingResult.responseCode}"
                    )
                }
            }

            override fun onBillingServiceDisconnected() {
                _connectionState.value = false
                SecurityAuditLog.logEvent(
                    "Billing service disconnected",
                    SecurityAuditLog.Severity.WARNING
                )
                // Retry connection with delay
                coroutineScope.launch {
                    delay(3000)
                    startConnection()
                }
            }
        })
    }

    suspend fun queryProducts(productIds: List<String>, isSubscription: Boolean = false): PaymentResult<List<ProductInfo>> {
        if (billingClient?.isReady != true) {
            return PaymentResult.Error(
                code = -1,
                message = "Billing client not ready"
            )
        }

        val productType = if (isSubscription) BillingClient.ProductType.SUBS else BillingClient.ProductType.INAPP

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    val products = productDetailsList.map { details ->
                        val pricing = details.oneTimePurchaseOfferDetails
                        ProductInfo(
                            productId = details.productId,
                            title = details.title,
                            description = details.description,
                            price = pricing?.formattedPrice ?: "N/A",
                            priceAmountMicros = pricing?.priceAmountMicros ?: 0L,
                            priceCurrencyCode = pricing?.priceCurrencyCode ?: "USD",
                            isSubscription = isSubscription
                        )
                    }
                    _availableProducts.value = products
                    SecurityAuditLog.logEvent("Products queried successfully", details = "Count: ${products.size}")
                    continuation.resumeWith(Result.success(PaymentResult.Success(products)))
                } else {
                    SecurityAuditLog.logEvent(
                        "Product query failed",
                        SecurityAuditLog.Severity.WARNING,
                        "Code: ${billingResult.responseCode}"
                    )
                    continuation.resumeWith(
                        Result.success(
                            PaymentResult.Error(
                                code = billingResult.responseCode,
                                message = billingResult.debugMessage
                            )
                        )
                    )
                }
            }
        }
    }

    suspend fun launchPurchaseFlow(
        activity: Activity,
        productId: String,
        isSubscription: Boolean = false
    ): PaymentResult<Transaction> {
        if (!DataSanitizer.isValidProductId(productId)) {
            SecurityAuditLog.logEvent(
                "Invalid product ID attempted",
                SecurityAuditLog.Severity.CRITICAL,
                "ProductId: $productId"
            )
            return PaymentResult.Error(code = -2, message = "Invalid product ID")
        }

        if (billingClient?.isReady != true) {
            return PaymentResult.Error(code = -1, message = "Billing client not ready")
        }

        val productType = if (isSubscription) BillingClient.ProductType.SUBS else BillingClient.ProductType.INAPP

        val productList = listOf(
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        )

        val queryParams = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.queryProductDetailsAsync(queryParams) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && productDetailsList.isNotEmpty()) {
                    val productDetails = productDetailsList.first()

                    val productDetailsParams = BillingFlowParams.ProductDetailsParams.newBuilder()
                        .setProductDetails(productDetails)

                    if (isSubscription) {
                        productDetails.subscriptionOfferDetails?.firstOrNull()?.let { offer ->
                            productDetailsParams.setOfferToken(offer.offerToken)
                        }
                    }

                    val billingFlowParams = BillingFlowParams.newBuilder()
                        .setProductDetailsParamsList(listOf(productDetailsParams.build()))
                        .build()

                    val transaction = Transaction(
                        type = if (isSubscription) TransactionType.SUBSCRIPTION else TransactionType.IN_APP_PURCHASE,
                        amount = (productDetails.oneTimePurchaseOfferDetails?.priceAmountMicros ?: 0L) / 1_000_000.0,
                        currency = productDetails.oneTimePurchaseOfferDetails?.priceCurrencyCode ?: "USD",
                        status = TransactionStatus.PROCESSING,
                        productId = productId,
                        description = productDetails.title
                    )

                    pendingPurchases[productId] = transaction

                    SecurityAuditLog.logEvent(
                        "Purchase flow launched",
                        details = "ProductId: $productId, TxId: ${transaction.id}"
                    )

                    val responseCode = billingClient?.launchBillingFlow(activity, billingFlowParams)

                    if (responseCode?.responseCode == BillingClient.BillingResponseCode.OK) {
                        continuation.resumeWith(Result.success(PaymentResult.Success(transaction)))
                    } else {
                        pendingPurchases.remove(productId)
                        continuation.resumeWith(
                            Result.success(
                                PaymentResult.Error(
                                    code = responseCode?.responseCode ?: -1,
                                    message = "Failed to launch billing flow"
                                )
                            )
                        )
                    }
                } else {
                    continuation.resumeWith(
                        Result.success(
                            PaymentResult.Error(
                                code = billingResult.responseCode,
                                message = "Product not found: $productId"
                            )
                        )
                    )
                }
            }
        }
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    coroutineScope.launch {
                        handlePurchase(purchase)
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                SecurityAuditLog.logEvent("Purchase cancelled by user")
                notifyPurchaseResult(
                    PaymentResult.Error(
                        code = BillingClient.BillingResponseCode.USER_CANCELED,
                        message = "Purchase cancelled by user"
                    )
                )
            }
            else -> {
                SecurityAuditLog.logEvent(
                    "Purchase failed",
                    SecurityAuditLog.Severity.WARNING,
                    "Code: ${billingResult.responseCode}, Message: ${billingResult.debugMessage}"
                )
                notifyPurchaseResult(
                    PaymentResult.Error(
                        code = billingResult.responseCode,
                        message = billingResult.debugMessage
                    )
                )
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            // Verify purchase signature
            if (!verifyPurchase(purchase)) {
                SecurityAuditLog.logEvent(
                    "Purchase verification failed",
                    SecurityAuditLog.Severity.CRITICAL,
                    "OrderId: ${purchase.orderId}"
                )
                notifyPurchaseResult(
                    PaymentResult.Error(code = -3, message = "Purchase verification failed")
                )
                return
            }

            // Acknowledge the purchase
            if (!purchase.isAcknowledged) {
                val acknowledgeParams = AcknowledgePurchaseParams.newBuilder()
                    .setPurchaseToken(purchase.purchaseToken)
                    .build()

                val result = withContext(Dispatchers.IO) {
                    billingClient?.acknowledgePurchase(acknowledgeParams)
                }

                if (result?.responseCode == BillingClient.BillingResponseCode.OK) {
                    val productId = purchase.products.firstOrNull() ?: ""
                    val transaction = pendingPurchases[productId]?.copy(
                        status = TransactionStatus.COMPLETED,
                        orderId = purchase.orderId,
                        purchaseToken = purchase.purchaseToken
                    ) ?: Transaction(
                        type = TransactionType.IN_APP_PURCHASE,
                        amount = 0.0,
                        status = TransactionStatus.COMPLETED,
                        productId = productId,
                        orderId = purchase.orderId,
                        purchaseToken = purchase.purchaseToken
                    )

                    pendingPurchases.remove(productId)
                    SecurityAuditLog.logEvent(
                        "Purchase completed and acknowledged",
                        details = "OrderId: ${purchase.orderId}, TxId: ${transaction.id}"
                    )
                    notifyPurchaseResult(PaymentResult.Success(transaction))
                } else {
                    SecurityAuditLog.logEvent(
                        "Purchase acknowledgement failed",
                        SecurityAuditLog.Severity.WARNING,
                        "Code: ${result?.responseCode}"
                    )
                }
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            SecurityAuditLog.logEvent("Purchase pending", details = "OrderId: ${purchase.orderId}")
            val productId = purchase.products.firstOrNull() ?: ""
            val transaction = pendingPurchases[productId]?.copy(
                status = TransactionStatus.PENDING,
                orderId = purchase.orderId
            ) ?: Transaction(
                type = TransactionType.IN_APP_PURCHASE,
                amount = 0.0,
                status = TransactionStatus.PENDING,
                productId = productId,
                orderId = purchase.orderId
            )
            notifyPurchaseResult(PaymentResult.Success(transaction))
        }
    }

    private fun verifyPurchase(purchase: Purchase): Boolean {
        // Basic verification - check that purchase data exists
        // In production, verify the signature server-side
        if (purchase.purchaseToken.isBlank()) {
            return false
        }
        if (purchase.products.isEmpty()) {
            return false
        }
        // TODO: Add server-side verification call here
        // This should send the purchase token to your backend for verification
        // with the Google Play Developer API
        return true
    }

    private suspend fun processPendingPurchases() {
        try {
            val inAppResult = billingClient?.queryPurchasesAsync(
                QueryPurchasesParams.newBuilder()
                    .setProductType(BillingClient.ProductType.INAPP)
                    .build()
            )

            inAppResult?.purchasesList?.forEach { purchase ->
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                    handlePurchase(purchase)
                }
            }

            val subsResult = billingClient?.queryPurchasesAsync(
                QueryPurchasesParams.newBuilder()
                    .setProductType(BillingClient.ProductType.SUBS)
                    .build()
            )

            subsResult?.purchasesList?.forEach { purchase ->
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                    handlePurchase(purchase)
                }
            }
        } catch (e: Exception) {
            SecurityAuditLog.logEvent(
                "Error processing pending purchases",
                SecurityAuditLog.Severity.WARNING,
                e.message ?: "Unknown error"
            )
        }
    }

    suspend fun consumePurchase(purchaseToken: String): PaymentResult<Boolean> {
        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.consumeAsync(consumeParams) { billingResult, _ ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    SecurityAuditLog.logEvent("Purchase consumed successfully")
                    continuation.resumeWith(Result.success(PaymentResult.Success(true)))
                } else {
                    continuation.resumeWith(
                        Result.success(
                            PaymentResult.Error(
                                code = billingResult.responseCode,
                                message = billingResult.debugMessage
                            )
                        )
                    )
                }
            }
        }
    }

    private fun notifyPurchaseResult(result: PaymentResult<Transaction>) {
        coroutineScope.launch(Dispatchers.Main) {
            onPurchaseCompleted?.invoke(result)
        }
    }

    fun destroy() {
        coroutineScope.cancel()
        billingClient?.endConnection()
        billingClient = null
        pendingPurchases.clear()
    }
}

