import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import kotlinx.coroutines.withContext

class WalletManager(context: Context) {

    private val secureStorage = SecureStorage(context)
    private val gson = Gson()
    private val transactionMutex = Mutex()

    private val _walletInfo = MutableStateFlow(WalletInfo())
    val walletInfo: StateFlow<WalletInfo> = _walletInfo.asStateFlow()

    private val _transactionHistory = MutableStateFlow<List<Transaction>>(emptyList())
    val transactionHistory: StateFlow<List<Transaction>> = _transactionHistory.asStateFlow()

    init {
        loadWalletState()
    }

    private fun loadWalletState() {
        val balance = secureStorage.getDouble(PaymentConfig.WALLET_BALANCE_KEY, 0.0)
        _walletInfo.value = WalletInfo(balance = DataSanitizer.sanitizeAmount(balance))

        val historyJson = secureStorage.getString(PaymentConfig.TRANSACTION_HISTORY_KEY, "[]")
        try {
            val type = object : TypeToken<List<Transaction>>() {}.type
            val history: List<Transaction> = gson.fromJson(historyJson, type) ?: emptyList()
            _transactionHistory.value = history
        } catch (e: Exception) {
            _transactionHistory.value = emptyList()
            SecurityAuditLog.logEvent(
                "Failed to load transaction history",
                SecurityAuditLog.Severity.WARNING,
                e.message ?: ""
            )
        }
    }

    private fun saveWalletState() {
        secureStorage.saveDouble(PaymentConfig.WALLET_BALANCE_KEY, _walletInfo.value.balance)
        val historyJson = gson.toJson(_transactionHistory.value)
        secureStorage.saveString(PaymentConfig.TRANSACTION_HISTORY_KEY, historyJson)
    }

    suspend fun topUp(amount: Double, description: String = "Wallet top-up"): PaymentResult<Transaction> {
        return processTransaction(
            type = TransactionType.WALLET_TOP_UP,
            amount = amount,
            description = description
        ) { currentBalance ->
            val newBalance = currentBalance + amount
            if (newBalance > PaymentConfig.MAX_WALLET_BALANCE) {
                throw WalletException("Top-up would exceed maximum wallet balance of ${PaymentConfig.MAX_WALLET_BALANCE}")
            }
            newBalance
        }
    }

    suspend fun withdraw(amount: Double, description: String = "Wallet withdrawal"): PaymentResult<Transaction> {
        return processTransaction(
            type = TransactionType.WALLET_WITHDRAWAL,
            amount = amount,
            description = description
        ) { currentBalance ->
            if (amount > currentBalance) {
                throw WalletException("Insufficient balance. Current: $currentBalance, Requested: $amount")
            }
            currentBalance - amount
        }
    }

    suspend fun transfer(
        amount: Double,
        recipientId: String,
        description: String = "Wallet transfer"
    ): PaymentResult<Transaction> {
        val sanitizedRecipientId = DataSanitizer.sanitizeString(recipientId)
        if (sanitizedRecipientId.isBlank()) {
            return PaymentResult.Error(code = -5, message = "Invalid recipient")
        }

        return processTransaction(
            type = TransactionType.WALLET_TRANSFER,
            amount = amount,
            description = description,
            metadata = mapOf("recipientId" to sanitizedRecipientId)
        ) { currentBalance ->
            if (amount > currentBalance) {
                throw WalletException("Insufficient balance for transfer")
            }
            currentBalance - amount
        }
    }

    suspend fun payWithWallet(
        amount: Double,
        productId: String,
        description: String = "In-app purchase via wallet"
    ): PaymentResult<Transaction> {
        if (!DataSanitizer.isValidProductId(productId)) {
            SecurityAuditLog.logEvent(
                "Invalid product ID in wallet payment",
                SecurityAuditLog.Severity.CRITICAL,
                "ProductId: $productId"
            )
            return PaymentResult.Error(code = -2, message = "Invalid product ID")
        }

        return processTransaction(
            type = TransactionType.IN_APP_PURCHASE,
            amount = amount,
            description = description,
            productId = productId
        ) { currentBalance ->
            if (amount > currentBalance) {
                throw WalletException("Insufficient wallet balance for purchase")
            }
            currentBalance - amount
        }
    }

    private suspend fun processTransaction(
        type: TransactionType,
        amount: Double,
        description: String,
        productId: String? = null,
        metadata: Map<String, String> = emptyMap(),
        balanceCalculator: (Double) -> Double
    ): PaymentResult<Transaction> = withContext(Dispatchers.IO) {
        transactionMutex.withLock {
            try {
                val sanitizedAmount = DataSanitizer.sanitizeAmount(amount)
                val sanitizedDescription = DataSanitizer.sanitizeString(description)

                if (!DataSanitizer.validateAmount(
                        sanitizedAmount,
                        PaymentConfig.MIN_TRANSACTION_AMOUNT,
                        PaymentConfig.MAX_TRANSACTION_AMOUNT
                    )
                ) {
                    SecurityAuditLog.logEvent(
                        "Invalid transaction amount",
                        SecurityAuditLog.Severity.WARNING,
                        "Amount: $sanitizedAmount"
                    )
                    return@withContext PaymentResult.Error(
                        code = -4,
                        message = "Amount must be between ${PaymentConfig.MIN_TRANSACTION_AMOUNT} and ${PaymentConfig.MAX_TRANSACTION_AMOUNT}"
                    )
                }

                if (_walletInfo.value.isLocked) {
                    SecurityAuditLog.logEvent(
                        "Transaction attempted on locked wallet",
                        SecurityAuditLog.Severity.CRITICAL
                    )
                    return@withContext PaymentResult.Error(
                        code = -6,
                        message = "Wallet is locked. Please contact support."
                    )
                }

                val currentBalance = _walletInfo.value.balance
                val newBalance = balanceCalculator(currentBalance)

                val transaction = Transaction(
                    type = type,
                    amount = sanitizedAmount,
                    status = TransactionStatus.COMPLETED,
                    description = sanitizedDescription,
                    productId = productId,
                    metadata = metadata
                )

                _walletInfo.value = _walletInfo.value.copy(
                    balance = DataSanitizer.sanitizeAmount(newBalance),
                    lastUpdated = System.currentTimeMillis()
                )

                val updatedHistory = _transactionHistory.value + transaction
                // Keep last 500 transactions
                _transactionHistory.value = if (updatedHistory.size > 500) {
                    updatedHistory.takeLast(500)
                } else {
                    updatedHistory
                }

                saveWalletState()

                SecurityAuditLog.logEvent(
                    "Transaction completed",
                    details = "Type: $type, Amount: $sanitizedAmount, TxId: ${transaction.id}, NewBalance: $newBalance"
                )

                PaymentResult.Success(transaction)
            } catch (e: WalletException) {
                SecurityAuditLog.logEvent(
                    "Transaction failed",
                    SecurityAuditLog.Severity.WARNING,
                    "Type: $type, Error: ${e.message}"
                )
                PaymentResult.Error(code = -7, message = e.message ?: "Transaction failed", exception = e)
            } catch (e: Exception) {
                SecurityAuditLog.logEvent(
                    "Unexpected transaction error",
                    SecurityAuditLog.Severity.CRITICAL,
                    "Type: $type, Error: ${e.message}"
                )
                PaymentResult.Error(code = -99, message = "Unexpected error occurred", exception = e)
            }
        }
    }

    suspend fun refundTransaction(transactionId: String): PaymentResult<Transaction> = withContext(Dispatchers.IO) {
        transactionMutex.withLock {
            val originalTransaction = _transactionHistory.value.find { it.id == transactionId }
                ?: return@withContext PaymentResult.Error(code = -8, message = "Transaction not found")

            if (originalTransaction.status != TransactionStatus.COMPLETED) {
                return@withContext PaymentResult.Error(code = -9, message = "Only completed transactions can be refunded")
            }

            val refundAmount = originalTransaction.amount
            val newBalance = _walletInfo.value.balance + refundAmount

            val refundTransaction = Transaction(
                type = originalTransaction.type,
                amount = refundAmount,
                status = TransactionStatus.REFUNDED,
                description = "Refund for transaction ${originalTransaction.id}",
                productId = originalTransaction.productId,
                metadata = mapOf("originalTransactionId" to originalTransaction.id)
            )

            // Update the original transaction status
            val updatedHistory = _transactionHistory.value.map {
                if (it.id == transactionId) it.copy(status = TransactionStatus.REFUNDED) else it
            } + refundTransaction

            _walletInfo.value = _walletInfo.value.copy(
                balance = DataSanitizer.sanitizeAmount(newBalance),
                lastUpdated = System.currentTimeMillis()
            )
            _transactionHistory.value = updatedHistory

            saveWalletState()

            SecurityAuditLog.logEvent(
                "Refund processed",
                details = "OriginalTxId: $transactionId, RefundTxId: ${refundTransaction.id}, Amount: $refundAmount"
            )

            PaymentResult.Success(refundTransaction)
        }
    }

    fun getBalance(): Double = _walletInfo.value.balance

    fun getTransactionById(transactionId: String): Transaction? {
        return _transactionHistory.value.find { it.id == transactionId }
    }

    fun getTransactionsByType(type: TransactionType): List<Transaction> {
        return _transactionHistory.value.filter { it.type == type }
    }

    fun getTransactionsByStatus(status: TransactionStatus): List<Transaction> {
        return _transactionHistory.value.filter { it.status == status }
    }

    suspend fun lockWallet() {
        transactionMutex.withLock {
            _walletInfo.value = _walletInfo.value.copy(isLocked = true)
            saveWalletState()
            SecurityAuditLog.logEvent("Wallet locked", SecurityAuditLog.Severity.CRITICAL)
        }
    }

    suspend fun unlockWallet() {
        transactionMutex.withLock {
            _walletInfo.value = _walletInfo.value.copy(isLocked = false)
            saveWalletState()
            SecurityAuditLog.logEvent("Wallet unlocked")
        }
    }

    fun clearAllData() {
        secureStorage.clear()
        _walletInfo.value = WalletInfo()
        _transactionHistory.value = emptyList()
        SecurityAuditLog.logEvent("All wallet data cleared", SecurityAuditLog.Severity.CRITICAL)
    }
}

class WalletException(message: String) : Exception(message)

