package com.payment.module

import android.app.Activity
import android.content.Context
import com.payment.module.billing.BillingManager
import com.payment.module.model.*
import com.payment.module.security.SecurityAuditLog
import com.payment.module.wallet.WalletManager
import kotlinx.coroutines.flow.StateFlow

class PaymentProcessor private constructor(
    private val context: Context
) {
    private var billingManager: BillingManager? = null
    private var walletManager: WalletManager? = null

    val walletInfo: StateFlow<WalletInfo>?
        get() = walletManager?.walletInfo

    val transactionHistory: StateFlow<List<Transaction>>?
        get() = walletManager?.transactionHistory

    val billingConnectionState: StateFlow<Boolean>?
        get() = billingManager?.connectionState

    val availableProducts: StateFlow<List<ProductInfo>>?
        get() = billingManager?.availableProducts

    companion object {
        @Volatile
        private var instance: PaymentProcessor? = null

        fun getInstance(context: Context): PaymentProcessor {
            return instance ?: synchronized(this) {
                instance ?: PaymentProcessor(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }

    fun initializeBilling(
        onPurchaseCompleted: ((PaymentResult<Transaction>) -> Unit)? = null
    ): PaymentProcessor {
        if (billingManager == null) {
            billingManager = BillingManager(context, onPurchaseCompleted)
            SecurityAuditLog.logEvent("Billing manager initialized")
        }
        return this
    }

    fun initializeWallet(): PaymentProcessor {
        if (walletManager == null) {
            walletManager = WalletManager(context)
            SecurityAuditLog.logEvent("Wallet manager initialized")
        }
        return this
    }

    // Billing operations
    suspend fun queryProducts(
        productIds: List<String>,
        isSubscription: Boolean = false
    ): PaymentResult<List<ProductInfo>> {
        return billingManager?.queryProducts(productIds, isSubscription)
            ?: PaymentResult.Error(code = -10, message = "Billing not initialized")
    }

    suspend fun purchaseProduct(
        activity: Activity,
        productId: String,
        isSubscription: Boolean = false
    ): PaymentResult<Transaction> {
        return billingManager?.launchPurchaseFlow(activity, productId, isSubscription)
            ?: PaymentResult.Error(code = -10, message = "Billing not initialized")
    }

    suspend fun consumePurchase(purchaseToken: String): PaymentResult<Boolean> {
        return billingManager?.consumePurchase(purchaseToken)
            ?: PaymentResult.Error(code = -10, message = "Billing not initialized")
    }

    // Wallet operations
    suspend fun topUpWallet(amount: Double, description: String = "Wallet top-up"): PaymentResult<Transaction> {
        return walletManager?.topUp(amount, description)
            ?: PaymentResult.Error(code = -11, message = "Wallet not initialized")
    }

    suspend fun withdrawFromWallet(amount: Double, description: String = "Withdrawal"): PaymentResult<Transaction> {
        return walletManager?.withdraw(amount, description)
            ?: PaymentResult.Error(code = -11, message = "Wallet not initialized")
    }

    suspend fun transferFromWallet(
        amount: Double,
        recipientId: String,
        description: String = "Transfer"
    ): PaymentResult<Transaction> {
        return walletManager?.transfer(amount, recipientId, description)
            ?: PaymentResult.Error(code = -11, message = "Wallet not initialized")
    }

    suspend fun payWithWallet(
        amount: Double,
        productId: String,
        description: String = "Purchase"
    ): PaymentResult<Transaction> {
        return walletManager?.payWithWallet(amount, productId, description)
            ?: PaymentResult.Error(code = -11, message = "Wallet not initialized")
    }

    suspend fun refundTransaction(transactionId: String): PaymentResult<Transaction> {
        return walletManager?.refundTransaction(transactionId)
            ?: PaymentResult.Error(code = -11, message = "Wallet not initialized")
    }

    fun getWalletBalance(): Double {
        return walletManager?.getBalance() ?: 0.0
    }

    fun getTransactionById(transactionId: String): Transaction? {
        return walletManager?.getTransactionById(transactionId)
    }

    fun getTransactionsByType(type: TransactionType): List<Transaction> {
        return walletManager?.getTransactionsByType(type) ?: emptyList()
    }

    suspend fun lockWallet() {
        walletManager?.lockWallet()
    }

    suspend fun unlockWallet() {
        walletManager?.unlockWallet()
    }

    fun getSecurityAuditLog(count: Int = 50): List<SecurityAuditLog.AuditEntry> {
        return SecurityAuditLog.getRecentEntries(count)
    }

    fun destroy() {
        billingManager?.destroy()
        billingManager = null
        walletManager = null
        instance = null
        SecurityAuditLog.logEvent("PaymentProcessor destroyed")
    }
}

