package com.payment.module.viewmodel

import android.app.Activity
import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.payment.module.PaymentProcessor
import com.payment.module.model.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

class PaymentViewModel(application: Application) : AndroidViewModel(application) {

    private val paymentProcessor = PaymentProcessor.getInstance(application)
        .initializeBilling { result ->
            _purchaseResult.value = result
        }
        .initializeWallet()

    val walletInfo = paymentProcessor.walletInfo!!
    val transactionHistory = paymentProcessor.transactionHistory!!
    val billingConnected = paymentProcessor.billingConnectionState!!
    val availableProducts = paymentProcessor.availableProducts!!

    private val _purchaseResult = MutableStateFlow<PaymentResult<Transaction>?>(null)
    val purchaseResult: StateFlow<PaymentResult<Transaction>?> = _purchaseResult.asStateFlow()

    private val _operationResult = MutableStateFlow<PaymentResult<Transaction>?>(null)
    val operationResult: StateFlow<PaymentResult<Transaction>?> = _operationResult.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    fun queryProducts(productIds: List<String>, isSubscription: Boolean = false) {
        viewModelScope.launch {
            _isLoading.value = true
            paymentProcessor.queryProducts(productIds, isSubscription)
            _isLoading.value = false
        }
    }

    fun purchaseProduct(activity: Activity, productId: String, isSubscription: Boolean = false) {
        viewModelScope.launch {
            _isLoading.value = true
            _purchaseResult.value = PaymentResult.Loading
            val result = paymentProcessor.purchaseProduct(activity, productId, isSubscription)
            if (result is PaymentResult.Error) {
                _purchaseResult.value = result
            }
            _isLoading.value = false
        }
    }

    fun topUpWallet(amount: Double, description: String = "Wallet top-up") {
        viewModelScope.launch {
            _isLoading.value = true
            _operationResult.value = PaymentResult.Loading
            _operationResult.value = paymentProcessor.topUpWallet(amount, description)
            _isLoading.value = false
        }
    }

    fun withdrawFromWallet(amount: Double, description: String = "Withdrawal") {
        viewModelScope.launch {
            _isLoading.value = true
            _operationResult.value = PaymentResult.Loading
            _operationResult.value = paymentProcessor.withdrawFromWallet(amount, description)
            _isLoading.value = false
        }
    }

    fun transferFromWallet(amount: Double, recipientId: String, description: String = "Transfer") {
        viewModelScope.launch {
            _isLoading.value = true
            _operationResult.value = PaymentResult.Loading
            _operationResult.value = paymentProcessor.transferFromWallet(amount, recipientId, description)
            _isLoading.value = false
        }
    }

    fun payWithWallet(amount: Double, productId: String, description: String = "Purchase") {
        viewModelScope.launch {
            _isLoading.value = true
            _operationResult.value = PaymentResult.Loading
            _operationResult.value = paymentProcessor.payWithWallet(amount, productId, description)
            _isLoading.value = false
        }
    }

    fun refundTransaction(transactionId: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _operationResult.value = PaymentResult.Loading
            _operationResult.value = paymentProcessor.refundTransaction(transactionId)
            _isLoading.value = false
        }
    }

    fun lockWallet() {
        viewModelScope.launch {
            paymentProcessor.lockWallet()
        }
    }

    fun unlockWallet() {
        viewModelScope.launch {
            paymentProcessor.unlockWallet()
        }
    }

    fun clearResults() {
        _purchaseResult.value = null
        _operationResult.value = null
    }

    fun getSecurityLog() = paymentProcessor.getSecurityAuditLog()

    override fun onCleared() {
        super.onCleared()
        // Don't destroy the processor here as it's a singleton
        // Only destroy when the app is being destroyed
    }
}

