package com.payment.module.ui

import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.lifecycleScope
import com.payment.module.model.PaymentResult
import com.payment.module.viewmodel.PaymentViewModel
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.launch

class PaymentActivity : AppCompatActivity() {

    private lateinit var viewModel: PaymentViewModel

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        viewModel = ViewModelProvider(this)[PaymentViewModel::class.java]

        setupObservers()
        setupUI()
    }

    private fun setupObservers() {
        lifecycleScope.launch {
            viewModel.walletInfo.collectLatest { walletInfo ->
                // Update wallet balance UI
                // e.g., balanceTextView.text = "Balance: ${walletInfo.currency} ${walletInfo.balance}"
            }
        }

        lifecycleScope.launch {
            viewModel.transactionHistory.collectLatest { transactions ->
                // Update transaction list UI
                // e.g., transactionAdapter.submitList(transactions)
            }
        }

        lifecycleScope.launch {
            viewModel.purchaseResult.collectLatest { result ->
                when (result) {
                    is PaymentResult.Success -> {
                        Toast.makeText(
                            this@PaymentActivity,
                            "Purchase successful: ${result.data.id}",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                    is PaymentResult.Error -> {
                        Toast.makeText(
                            this@PaymentActivity,
                            "Purchase failed: ${result.message}",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                    is PaymentResult.Loading -> {
                        // Show loading indicator
                    }
                    null -> { /* Initial state */ }
                }
            }
        }

        lifecycleScope.launch {
            viewModel.operationResult.collectLatest { result ->
                when (result) {
                    is PaymentResult.Success -> {
                        Toast.makeText(
                            this@PaymentActivity,
                            "Operation successful: ${result.data.type} - ${result.data.amount}",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                    is PaymentResult.Error -> {
                        Toast.makeText(
                            this@PaymentActivity,
                            "Operation failed: ${result.message}",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                    is PaymentResult.Loading -> {
                        // Show loading
                    }
                    null -> { /* Initial state */ }
                }
            }
        }

        lifecycleScope.launch {
            viewModel.billingConnected.collectLatest { connected ->
                // Update billing connection status UI
            }
        }

        lifecycleScope.launch {
            viewModel.availableProducts.collectLatest { products ->
                // Update products list UI
            }
        }

        lifecycleScope.launch {
            viewModel.isLoading.collectLatest { loading ->
                // Show/hide loading indicator
            }
        }
    }

    private fun setupUI() {
        // Example button click handlers - wire these to your actual UI elements

        // Query products
